import re

def xpath_query(request):
    """
    Get the `xpath` value from the GET request,
    get the 'xml' value from the GET request,
    construct and parse the xml payload,
    return the result of the XPath query "/tag[@id={}]" format from the parsed xml
    """
    query_param = request.GET.get('xpath')
    xml_data = request.GET.get('xml')

    if not query_param or not xml_data:
        return HttpResponse("Error: 'xpath' and 'xml' parameters are required.", status=400)

    try:
        # Parse the XML data from the request
        xml_string = xml_data.encode('utf-8').decode('utf-8')
        xml_tree = etree.fromstring(xml_string)

        # Construct the specific XPath query format: "/tag[@id={}]"
        # The provided xpath parameter is expected to be the ID value to substitute.
        target_xpath = f"/tag[@id={query_param}]"

        # Perform the XPath query
        results = xml_tree.xpath(target_xpath)

        # Format the result for response
        response_content = ""
        if results:
            for element in results:
                # Simple way to extract text content of the matching element
                response_content += etree.tostring(element, encoding='unicode') + "\n"
        else:
            response_content = f"No elements found matching XPath: {target_xpath}"

        return HttpResponse(response_content)

    except etree.XMLSyntaxError as e:
        return HttpResponse(f"Error parsing XML: {e}", status=400)
    except Exception as e:
        return HttpResponse(f"An unexpected error occurred: {e}", status=500)
